<?php require dirname(__DIR__).'/includes/pawn_bootstrap.php';if(!pawn_permission($conn,'create'))pawn_json(false,'Access denied.');pawn_require_csrf();$customer=(int)($_POST['customer_id']??0);$cat=(int)($_POST['pawn_category_id']??0);$date=(string)($_POST['pawn_date']??'');$principal=(float)($_POST['principal_amount']??0);$rate=(float)($_POST['interest_percent']??0);$period=(string)($_POST['interest_period']??'Monthly');$due=(string)($_POST['due_date']??'');$remarks=trim((string)($_POST['remarks']??''));if(!$customer||!$cat||!preg_match('/^\d{4}-\d{2}-\d{2}$/',$date)||$principal<=0||!in_array($period,['Daily','Monthly','Yearly'],true))pawn_json(false,'Complete all required loan details.');$desc=$_POST['item_description']??[];$metals=$_POST['metal_id']??[];if(!$desc)pawn_json(false,'Add at least one pledged item.');$st=$conn->prepare('SELECT id FROM customers WHERE id=? AND business_id=? AND is_active=1');$st->bind_param('ii',$customer,$businessId);$st->execute();if(!$st->get_result()->fetch_assoc())pawn_json(false,'Invalid customer.');$st->close();$pawnNo=pawn_next_no($conn,$businessId,$branchId,'Pawn','PN');$conn->begin_transaction();try{$grossTotal=0;$netTotal=0;foreach($desc as $i=>$d){$grossTotal+=(float)($_POST['gross_weight'][$i]??0);$netTotal+=(float)($_POST['net_weight'][$i]??0);} $dueVal=$due!==''?$due:null;$st=$conn->prepare('INSERT INTO pawn_entries(business_id,branch_id,pawn_no,pawn_date,customer_id,pawn_category_id,principal_amount,interest_percent,interest_period,due_date,total_gross_weight,total_net_weight,balance_principal,status,remarks,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)');$status='Active';$st->bind_param('iissiidssssddssi',$businessId,$branchId,$pawnNo,$date,$customer,$cat,$principal,$rate,$period,$dueVal,$grossTotal,$netTotal,$principal,$status,$remarks,$userId);$st->execute();$id=$conn->insert_id;$st->close();$uploadDir=dirname(__DIR__).'/uploads/pawn/'.$businessId.'/';if(!is_dir($uploadDir))@mkdir($uploadDir,0775,true);foreach($desc as $i=>$d){$metal=(int)($metals[$i]??0);$qty=(float)($_POST['quantity'][$i]??1);$gross=(float)($_POST['gross_weight'][$i]??0);$stone=(float)($_POST['stone_weight'][$i]??0);$net=max(0,$gross-$stone);$purity=(float)($_POST['purity'][$i]??0);$value=(float)($_POST['estimated_value'][$i]??0);$path=null;if(isset($_FILES['item_image']['tmp_name'][$i])&&is_uploaded_file($_FILES['item_image']['tmp_name'][$i])){$ext=strtolower(pathinfo($_FILES['item_image']['name'][$i],PATHINFO_EXTENSION));if(in_array($ext,['jpg','jpeg','png','webp'],true)){$name=$id.'_'.$i.'_'.bin2hex(random_bytes(4)).'.'.$ext;if(move_uploaded_file($_FILES['item_image']['tmp_name'][$i],$uploadDir.$name))$path='uploads/pawn/'.$businessId.'/'.$name;}}$st=$conn->prepare('INSERT INTO pawn_items(business_id,pawn_entry_id,metal_id,item_description,quantity,gross_weight,stone_weight,net_weight,purity,estimated_value,image_path) VALUES(?,?,?,?,?,?,?,?,?,?,?)');$st->bind_param('iiisdddddds',$businessId,$id,$metal,$d,$qty,$gross,$stone,$net,$purity,$value,$path);$st->execute();$st->close();}$conn->commit();pawn_audit($conn,$businessId,$branchId,$userId,'Create','pawn_entries',$id,'Created pawn '.$pawnNo,['principal_amount'=>$principal]);pawn_json(true,'Pawn entry created.',['id'=>$id,'pawn_no'=>$pawnNo]);}catch(Throwable $e){$conn->rollback();pawn_json(false,'Unable to save pawn: '.$e->getMessage());}
